import { describe, it, expect } from 'vitest';
import { projectEntropy, collapseWavefunction } from '../void-combat-engine';
import { createObserver } from '../void-game-engine';
import type { DimensionIndex } from '../void-game-types';

describe('void-combat-engine (Upward Vulnerability & Wavefunction Collapse)', () => {
  const baseObserver = createObserver('aggressor-1', 42, 'scientist', 'builder', 'anyon');

  it('allows a lower-dimensional observer to project entropy UP at a higher dimension', () => {
    // Aggressor is Dim 0
    // Target is Dim 3
    const result = projectEntropy(baseObserver, 'target-dim3', 3, 'shard-x', 10);
    
    expect(result.events.length).toBeGreaterThan(0);
    expect(result.state.energy).toBe(baseObserver.energy - 10);
    expect(result.state.sin).toBeGreaterThan(0); // Aggressive action causes sin
    expect(result.combatState.targetDimension).toBe(3);
  });

  it('allows an observer to attack someone in the same dimension', () => {
    const dim3Observer = { ...baseObserver, coordinate: { ...baseObserver.coordinate, dimension: 3 as DimensionIndex } };
    
    const result = projectEntropy(dim3Observer, 'target-dim3', 3, 'shard-x', 50);
    expect(result.combatState.investedEnergy).toBe(50);
  });

  it('PREVENTS a higher-dimensional observer from projecting entropy DOWN', () => {
    // Aggressor is Dim 7, Target is Dim 2
    const highDimObserver = { ...baseObserver, coordinate: { ...baseObserver.coordinate, dimension: 7 as DimensionIndex } };
    
    expect(() => {
      projectEntropy(highDimObserver, 'target-dim2', 2, 'shard-y', 10);
    }).toThrow(/Cannot project entropy downward/);
  });

  it('allows a higher-dimensional observer to collapse their wavefunction to engage', () => {
    const highDimObserver = { ...baseObserver, coordinate: { ...baseObserver.coordinate, dimension: 7 as DimensionIndex }, energy: 1000 };
    
    // Collapse to Dim 2
    const collapseResult = collapseWavefunction(highDimObserver, 2);
    
    // Dimension should now be 2
    expect(collapseResult.state.coordinate.dimension).toBe(2);
    
    // Collapsing costs energy proportional to distance (7 - 2 = 5)  (10% per level) * 0.8 scientist modifier => 400 cost
    expect(collapseResult.state.energy).toBe(600); 
    expect(collapseResult.events[0]?.type).toBe('wavefunction_collapsed');

    // And NOW they can project entropy at Dim 2
    // Invested 100 energy. Scientist entropy projection costs 100 directly. 600 - 100 = 500.
    const attackResult = projectEntropy(collapseResult.state, 'target-dim2', 2, 'shard-y', 100);
    expect(attackResult.state.energy).toBe(500); // 600 - 100
  });

  it('prevents wavefunction collapse if attempting to go up or stay equal', () => {
    const dim4Observer = { ...baseObserver, coordinate: { ...baseObserver.coordinate, dimension: 4 as DimensionIndex } };

    expect(() => collapseWavefunction(dim4Observer, 5)).toThrow(/only for moving to a lower dimension/);
    expect(() => collapseWavefunction(dim4Observer, 4)).toThrow(/only for moving to a lower dimension/);
  });
});
